import { User, Order, Product } from './types';

function generateUser(id: number): User {
  return {
    id: `user_${id}`,
    name: `User ${id}`,
    email: `user${id}@example.com`,
    lastActiveTimestamp: 1618025200000 + Math.floor(Math.random() * 86400000), // 24h range
    balanceCents: Math.floor(Math.random() * 1000000) // 0-999,999 cents
  };
}

function generateProduct(id: number): Product {
  const categories = ['electronics', 'books', 'clothing', 'furniture'];
  return {
    id: `product_${id}`,
    name: `Product ${id}`,
    priceCents: Math.floor(Math.random() * 1000000) + 100, // 100-999,999 cents
    category: categories[Math.floor(Math.random() * categories.length)]
  };
}

function generateOrder(id: number, userId: string, productId: string): Order {
  return {
    id: `order_${id}`,
    userId,
    productId,
    createdAt: 1618025200000 + Math.floor(Math.random() * 86400000),
    amountCents: Math.floor(Math.random() * 1000000) + 100
  };
}

export function generateSampleData(): { users: User[], orders: Order[], products: Product[] } {
  const users = [];
  const products = [];
  const orders = [];

  for (let i = 1; i <= 5; i++) {
    users.push(generateUser(i));
    products.push(generateProduct(i));
  }

  for (let i = 1; i <= 5; i++) {
    orders.push(generateOrder(i, users[i-1].id, products[i-1].id));
  }

  return { users, orders, products };
}
