## Phase 4: Validator (validate.ts)
```typescript
// validate.ts
import { User, Order, Product } from './types';

function isValidId(id: string): boolean {
  const entityTypes = ['user_', 'order_', 'product_'];
  return entityTypes.some(type => id.startsWith(type));
}

function isValidTimestamp(timestamp: number): boolean {
  return typeof timestamp === 'number' && !isNaN(timestamp);
}

function isValidCents(cents: number): boolean {
  return typeof cents === 'number' && !isNaN(cents) && isFinite(cents);
}

function validateUser(user: User): string[] {
  const errors = [];

  if (!isValidId(user.id)) {
    errors.push(`User ID ${user.id} is invalid`);
  }

  if (!isValidTimestamp(user.lastActiveTimestamp)) {
    errors.push(`User timestamp ${user.lastActiveTimestamp} is invalid`);
  }

  if (!isValidCents(user.balanceCents)) {
    errors.push(`User balance ${user.balanceCents} is invalid`);
  }

  return errors;
}

function validateOrder(order: Order): string[] {
  const errors = [];

  if (!isValidId(order.id)) {
    errors.push(`Order ID ${order.id} is invalid`);
  }

  if (!isValidId(order.userId)) {
    errors.push(`Order user ID ${order.userId} is invalid`);
  }

  if (!isValidId(order.productId)) {
    errors.push(`Order product ID ${order.productId} is invalid`);
  }

  if (!isValidTimestamp(order.createdAt)) {
    errors.push(`Order timestamp ${order.createdAt} is invalid`);
  }

  if (!isValidCents(order.amountCents)) {
    errors.push(`Order amount ${order.amountCents} is invalid`);
  }

  return errors;
}

function validateProduct(product: Product): string[] {
  const errors = [];

  if (!isValidId(product.id)) {
    errors.push(`Product ID ${product.id} is invalid`);
  }

  if (!isValidCents(product.priceCeter)) { // Note: typo in original code, should be priceCents
    errors.push(`Product price ${product.priceCents} is invalid`);
  }

  return errors;
}

export function validateData(data: { users: User[], orders: Order[], products: Product[] }): { valid: boolean, errors: string[] } {
  const errors: string[] = [];

  data.users.forEach(user => {
    errors.push(...validateUser(user));
  });

  data.orders.forEach(order => {
    errors.push(...validateOrder(order));
  });

  data.products.forEach(product => {
    errors.push(...validateProduct(product));
  });

  return { valid: errors.length === 0, errors };
}
```

