// validate.ts
import { User, Order, Product } from './types';
import { users, products, orders } from './generate';

function isValidId(id: string): boolean {
  if (id.startsWith("user_")) return true;
  if (id.startsWith("order_")) return true;
  if (id.startsWith("product_")) return true;
  return false;
}

function isValidTimestamp(timestamp: number): boolean {
  return typeof timestamp === 'number' && !isNaN(timestamp);
}

function isValidCents(value: number): boolean {
  return typeof value === 'number' && !isNaN(value) && Number.isInteger(value);
}

function validateUser(user: User): string[] {
  const errors: string[] = [];
  if (!isValidId(user.id)) errors.push(`Invalid user ID format: ${user.id}`);
  if (!isValidCents(user.balance)) errors.push(`Invalid balance: ${user.balance}`);
  return errors;
}

function validateOrder(order: Order): string[] {
  const errors: string[] = [];
  if (!isValidId(order.id)) errors.push(`Invalid order ID format: ${order.id}`);
  if (!isValidId(order.userId)) errors.push(`Invalid user ID in order: ${order.userId}`);
  if (!isValidId(order.productId)) errors.push(`Invalid product ID in order: ${order.productId}`);
  if (!isValidCents(order.amount)) errors.push(`Invalid amount: ${order.amount}`);
  if (!isValidTimestamp(order.timestamp)) errors.push(`Invalid timestamp: ${order.timestamp}`);
  return errors;
}

function validateProduct(product: Product): string[] {
  const errors: string[] = [];
  if (!isValidId(product.id)) errors.push(`Invalid product ID format: ${product.id}`);
  if (!isValidCents(product.price)) errors.push(`Invalid price: ${product.price}`);
  if (!isValidTimestamp(product.creationTimestamp)) errors.push(`Invalid creation timestamp: ${product.creationTimestamp}`);
  return errors;
}

function validateAllData(): { valid: boolean; errors: string[] } {
  const allErrors: string[] = [];

  // Validate users
  for (const user of users) {
    const userErrors = validateUser(user);
    allErrors.push(...userErrors);
  }

  // Validate products
  for (const product of products) {
    const productErrors = validateProduct(product);
    allErrors.push(...productErrors);
  }

  // Validate orders
  for (const order of orders) {
    const orderErrors = validateOrder(order);
    allErrors.push(...orderErrors);
  }

  return { valid: allErrors.length === 0, errors: allErrors };
}

export default validateAllData;
