// validate.ts
import { User, Order, Product } from './types';

function isValidId(id: string): boolean {
  if (!id.startsWith('user_') && !id.startsWith('order_') && !id.startsWith('product_')) {
    return false;
  }
  return id.length > 6; // Ensure ID has at least 6 characters after prefix
}

function isValidTimestamp(timestamp: number): boolean {
  return typeof timestamp === 'number' && !isNaN(timestamp);
}

function isValidCents(value: number): boolean {
  return typeof value === 'number' && !isNaN(value) && value % 1 === 0;
}

function isValidOrder(order: Order): boolean {
  if (!isValidId(order.id)) return false;
  if (!isValidTimestamp(order.timestamp)) return false;
  if (!isValidCents(order.totalCents)) return false;

  // Check that totalCents matches sum of product prices
  // (In a real system, this would look up products by ID)
  const products = order.productIds.map(id => {
    // For simplicity, we'll assume products are already generated
    // In a real system, this would look up products by ID
    return { id, priceCents: Math.floor(Math.random() * 1000000) };
  });

  const total = products.reduce((sum, product) => sum + product.priceCents, 0);
  return order.totalCents === total;
}

function isValidUser(user: User): boolean {
  if (!isValidId(user.id)) return false;
  if (!isValidTimestamp(user.timestamp)) return false;
  if (!isValidCents(user.balance)) return false;

  return true;
}

function isValidProduct(product: Product): boolean {
  if (!isValidId(product.id)) return false;
  if (!isValidTimestamp(product.timestamp)) return false;
  if (!isValidCents(product.priceCents)) return false;

  return true;
}

export function validateData(users: User[], products: Product[], orders: Order[]): void {
  console.log('Validating data...');

  // Validate users
  for (const user of users) {
    if (!isValidUser(user)) {
      console.error(`Invalid user: ${user.id}`);
      console.error('Error: User must have valid ID, timestamp, and balance');
    }
  }

  // Validate products
  for (const product of products) {
    if (!isValidProduct(product)) {
      console.error(`Invalid product: ${product.id}`);
      console.error('Error: Product must have valid ID, timestamp, and price');
    }
  }

  // Validate orders
  for (const order of orders) {
    if (!isValidOrder(order)) {
      console.error(`Invalid order: ${order.id}`);
      console.error('Error: Order must have valid ID, timestamp, and totalCents');
    }
  }

  console.log('All data validation passed');
}
