// validate.ts

import { IUser, IOrder, IProduct } from './types';
import { dataGenerator } from './generate';

export const validator = () => {
    const data = dataGenerator();
    const errors: string[] = [];

    // Validate users
    for (const user of data.users) {
        if (!user.id.startsWith('user_')) {
            errors.push(`Invalid user ID format: ${user.id}`);
        }

        if (typeof user.balanceCents !== 'number' || user.balanceCents < 0) {
            errors.push(`Invalid user balance cents: ${user.balanceCents}`);
        }
    }

    // Validate orders
    for (const order of data.orders) {
        if (!order.id.startsWith('order_')) {
            errors.push(`Invalid order ID format: ${order.id}`);
        }

        const user = data.users.find(u => u.id === order.userId);
        if (!user || typeof user.balanceCents !== 'number') {
            errors.push(`Invalid order userId reference`);
        }

        if (typeof order.totalCents !== 'number' || order.totalCents < 0) {
            errors.push(`Invalid order total cents: ${order.totalCents}`);
        }
    }

    // Validate products
    for (const product of data.products) {
        if (!product.id.startsWith('product_')) {
            errors.push(`Invalid product ID format: ${product.id}`);
        }

        if (typeof product.priceCents !== 'number' || product.priceCents < 0) {
            errors.push(`Invalid product price cents: ${product.priceCents}`);
        }

        if (!Number.isInteger(product.stockQuantity) || product.stockQuantity < 0) {
            errors.push(`Invalid product stock quantity: ${product.stockQuantity}`);
        }
    }

    return { data, errors };
};
