```typescript
// validate.ts

import { User } from './types';
import { Order } from './types';
import { Product } from './types';

function validateUsers(users: User[]): boolean {
  return users.every(user => {
    const hasValidEmail = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(user.email);
    const hasPositiveBalance = user.balanceCents > 0;
    const hasValidIDPrefix = user.id.startsWith('user_');

    return hasValidEmail && hasPositiveBalance && hasValidIDPrefix;
  });
}

function validateProducts(products: Product[]): boolean {
  return products.every(product => {
    const hasValidPrice = product.priceCents > 0;
    const hasValidIDPrefix = product.id.startsWith('product_');
    const hasNonEmptyName = product.name.length > 0;

    return hasValidPrice && hasValidIDPrefix && hasNonEmptyName;
  });
}

function validateOrders(orders: Order[], users: User[]): boolean {
  return orders.every(order => {
    const hasValidUser = users.some(user => user.id === order.userId);
    const hasValidProduct = products.some(product => product.id === order.productId);
    const hasPositiveQuantity = order.quantity > 0;
    const hasValidTotal = order.totalCents >= order.quantity * (product.priceCents / 100);

    return hasValidUser && hasValidProduct && hasPositiveQuantity && hasValidTotal;
  });
}

function validateTimestamps(data: User | Order | Product): boolean {
  const isUnixTime = data.createdAt === Math.floor(Date.now());
  return isUnixTime;
}

export function validateAll(users: User[], products: Product[], orders: Order[]): { valid: boolean; errors: string[] } {
  const usersValid = validateUsers(users);
  const productsValid = validateProducts(products);
  const ordersValid = validateOrders(orders, users);

  if (!usersValid || !productsValid || !ordersValid) {
    return {
      valid: false,
      errors: [
        ...(usersValid ? [] : ['Invalid user data']),
        ...(productsValid ? [] : ['Invalid product data']),
        ...(ordersValid ? [] : ['Invalid order data']),
      ]
    };
  }

  const allValid = users.every(user => validateTimestamps(user)) &&
                   products.every(product => validateTimestamps(product)) &&
                   orders.every(order => validateTimestamps(order));

  return {
    valid: allValid,
    errors: allValid ? [] : ['Invalid timestamp']
  };
}
