// validate.ts
import { User, Order, Product } from './types';

export function validateEntity(entity: EntityBase): boolean {
  const idPrefix = entity.id?.substring(0, 5); // Check for "user_", "order_", or "product_"

  return (
    idPrefix === 'user_' ||
    idPrefix === 'order_' ||
    idPrefix === 'product_'
  );
}

export function validateUser(user: User): boolean {
  const validId = user.id?.startsWith('user_');
  const validName = typeof user.name === 'string' && user.name.length > 0;
  const validEmail = 
    typeof user.email === 'string' && 
    user.email.includes('@') && 
    user.email.length > 5;

  return (
    validateEntity(user) &&
    validId &&
    validName &&
    validEmail
  );
}

export function validateOrder(order: Order): boolean {
  const validId = order.id?.startsWith('order_');
  const validUserId = typeof order.userId === 'string' && order.userId.length > 5;
  const validTotalCents = Number.isInteger(order.totalCents) && order.totalCents >= 0;

  return (
    validateEntity(order) &&
    validId &&
    validUserId &&
    validTotalCents
  );
}

export function validateProduct(product: Product): boolean {
  const validId = product.id?.startsWith('product_');
  const validName = typeof product.name === 'string' && product.name.length > 0;
  const validPriceCents = Number.isInteger(product.priceCents) && product.priceCents >= 0;

  return (
    validateEntity(product) &&
    validId &&
    validName &&
    validPriceCents
  );
}
