```typescript
// validate.ts
import { User } from './types';
import { Order } from './types';
import { Product } from './types';

async function validate(data: {
  users: User[];
  orders: Order[];
  products: Product[];
}) {
  const violations = [];

  // Validate Users
  data.users.forEach((user) => {
    if (!user.user_id.startsWith('user_')) {
      violations.push(`Invalid user ID: ${user.user_id}`);
    }
    if (typeof user.created_at !== 'number' || user.created_at < 0) {
      violations.push(`Invalid created_at for user: ${user.created_at}`);
    }
    // Validate email format
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(user.email)) {
      violations.push(`Invalid email format: ${user.email}`);
    }
  });

  // Validate Orders
  data.orders.forEach((order) => {
    if (!order.order_id.startsWith('order_')) {
      violations.push(`Invalid order ID: ${order.order_id}`);
    }
    if (typeof order.total_cents !== 'number' || order.total_cents < 0) {
      violations.push(`Invalid total_cents for order: ${order.total_cents}`);
    }
    if (!['pending', 'shipped', 'delivered'].includes(order.status)) {
      violations.push(`Invalid status for order: ${order.status}`);
    }
  });

  // Validate Products
  data.products.forEach((product) => {
    if (!product.product_id.startsWith('product_')) {
      violations.push(`Invalid product ID: ${product.product_id}`);
    }
    if (typeof product.price_cents !== 'number' || product.price_cents < 0) {
      violations.push(`Invalid price_cents for product: ${product.price_cents}`);
    }
    if (typeof product.stock_quantity !== 'number' || product.stock_quantity < 0) {
      violations.push(`Invalid stock_quantity for product: ${product.stock_quantity}`);
    }
  });

  return { valid: violations.length === 0, violations };
}

export default validate;
